  5→//! Gallops I/O operations with validation
  6→//!
  7→//! Provides validated load/save operations for Gallops JSON with round-trip guarantees.
  8→
  9→use std::fs;
 10→use std::path::Path;
 11→use crate::jjrt_types::jjrg_Gallops;
 12→use crate::jjrv_validate::jjrg_validate;
 13→
 14→/// Validated Gallops wrapper
 15→///
 16→/// This newtype ensures that Gallops instances are validated on load.
 17→/// Only jjdr_load can create instances, guaranteeing all ValidatedGallops
 18→/// have passed both deserialization and semantic validation.
 19→pub struct jjdr_ValidatedGallops(jjrg_Gallops);
 20→
 21→impl jjdr_ValidatedGallops {
 22→    /// Access the inner Gallops (immutable)
 23→    pub fn inner(&self) -> &jjrg_Gallops {
 24→        &self.0
 25→    }
 26→
 27→    /// Access the inner Gallops (mutable)
 28→    pub fn inner_mut(&mut self) -> &mut jjrg_Gallops {
 29→        &mut self.0
 30→    }
 31→
 32→    /// Consume the wrapper and return the inner Gallops
 33→    pub fn into_inner(self) -> jjrg_Gallops {
 34→        self.0
 35→    }
 36→
 37→    /// Test-only constructor (bypasses validation)
 38→    #[cfg(test)]
 39→    pub fn test_wrap(g: jjrg_Gallops) -> Self {
 40→        Self(g)
 41→    }
 42→}
 43→
 44→/// Find first byte position where two byte slices differ
 45→fn zjjdr_find_first_diff(a: &[u8], b: &[u8]) -> usize {
 46→    a.iter()
 47→        .zip(b.iter())
 48→        .position(|(x, y)| x != y)
 49→        .unwrap_or_else(|| a.len().min(b.len()))
 50→}
 51→
 52→/// Encode a firemark string into a case-safe paddock filename path.
 53→///
 54→/// Each character is prefixed with 'u' (uppercase) or 'l' (lowercase),
 55→/// ensuring the resulting filename is unambiguous on case-insensitive
 56→/// filesystems (macOS HFS+/APFS).
 57→///
 58→/// Examples:
 59→///   "AG" → ".claude/jjm/jjp_uAuG.md"
 60→///   "Ag" → ".claude/jjm/jjp_uAlg.md"
 61→///   "ag" → ".claude/jjm/jjp_lalg.md"
 62→pub fn jjri_paddock_path(firemark: &str) -> String {
 63→    let encoded: String = firemark.chars().map(|c| {
 64→        if c.is_uppercase() {
 65→            format!("u{}", c)
 66→        } else {
 67→            format!("l{}", c)
 68→        }
 69→    }).collect();
 70→    format!(".claude/jjm/jjp_{}.md", encoded)
 71→}
 72→
 73→/// Load and validate Gallops from a file
 74→///
 75→/// Performs these steps in order:
 76→/// 1. Deserialize JSON to Gallops struct
 77→/// 2. Round-trip validation: reserialize and compare bytes (validates stored format)
 78→/// 3. Recompute paddock_file from firemark for every heat (JJK owns this field)
 79→/// 4. Paddock existence check: fatal with mv instructions if files are at legacy paths
 80→/// 5. Semantic validation via jjrg_validate
 81→///
 82→/// Step 3 means the stored paddock_file value is ignored — JJK always derives it from
 83→/// the firemark. After migration, the next save writes the encoded value back to disk.
 84→///
 85→/// Returns ValidatedGallops wrapper that guarantees the data has passed all checks.
 86→pub fn jjdr_load(path: &Path) -> Result<jjdr_ValidatedGallops, String> {
 87→    // Read original bytes
 88→    let original_bytes = fs::read(path)
 89→        .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
 90→
 91→    // Deserialize (mut: paddock_file will be recomputed below)
 92→    let mut gallops: jjrg_Gallops = serde_json::from_slice(&original_bytes)
 93→        .map_err(|e| format!("Failed to parse JSON: {}", e))?;
 94→
 95→    // Detect old-format files: heat_order absent in JSON → serde default → empty vec.
 96→    // Old-format files cannot pass round-trip check because BTreeMap serializes heats
 97→    // in sorted key order, which differs from original furlough-shuffled order.
 98→    let is_migration_mode = gallops.heat_order.is_empty();
 99→
100→    // Round-trip validation: run before recomputation to validate the stored format.
101→    // Skipped for old-format files (heat_order empty) — BTreeMap key order differs from
102→    // original IndexMap insertion order, so round-trip will always fail for these files.
103→    if !is_migration_mode {
104→        let reserialized = serde_json::to_string_pretty(&gallops)
105→            .map_err(|e| format!("Failed to reserialize JSON: {}", e))?;
106→
107→        if reserialized.as_bytes() != original_bytes {
108→            let diff_pos = zjjdr_find_first_diff(&original_bytes, reserialized.as_bytes());
109→            return Err(format!("Round-trip validation failed at byte {}", diff_pos));
110→        }
111→    }
112→
113→    // Recompute paddock_file from firemark for every heat.
114→    // JJK owns this field exclusively; whatever is stored in JSON is overwritten.
115→    // This allows old gallops files (with raw-firemark paths) to load transparently —
116→    // the correct encoded path is used in memory, and written back on the next save.
117→    for (firemark_key, heat) in &mut gallops.heats {
118→        let bare = firemark_key.trim_start_matches('₣');
119→        heat.paddock_file = jjri_paddock_path(bare);
120→    }
121→
122→    // Populate heat_order from sorted heats keys on first load of old-format file.
123→    // BTreeMap guarantees sorted key order here.
124→    if is_migration_mode {
125→        gallops.heat_order = gallops.heats.keys().cloned().collect();
126→    }
127→
128→    // Paddock existence check: verify each encoded paddock file exists on disk.
129→    // If missing, compute the legacy raw-firemark path and emit mv instructions.
130→    // Reports ALL missing files at once so a single repair pass suffices.
131→    {
132→        let mut repairs: Vec<String> = Vec::new();
133→        for (firemark_key, heat) in &gallops.heats {
134→            if !Path::new(&heat.paddock_file).exists() {
135→                let bare = firemark_key.trim_start_matches('₣');
136→                let legacy_path = format!(".claude/jjm/jjp_{}.md", bare);
137→                if Path::new(&legacy_path).exists() {
138→                    repairs.push(format!("  mv {} {}", legacy_path, heat.paddock_file));
139→                } else {
140→                    repairs.push(format!(
141→                        "  # WARNING: paddock missing for heat \"{}\", expected: {}",
142→                        bare, heat.paddock_file
143→                    ));
144→                }
145→            }
146→        }
147→        if !repairs.is_empty() {
148→            return Err(format!(
149→                "Paddock files need renaming before proceeding:\n\n{}",
150→                repairs.join("\n")
151→            ));
152→        }
153→    }
154→
155→    // Semantic validation
156→    jjrg_validate(&gallops)
157→        .map_err(|errors| format!("Validation failed: {}", errors.join("; ")))?;
158→
159→    Ok(jjdr_ValidatedGallops(gallops))
160→}
