  5→//! Gallops validation routines
  6→//!
  7→//! Validates Gallops JSON structure against schema rules.
  8→
  9→use std::collections::HashSet;
 10→use crate::jjrf_favor::JJRF_CHARSET;
 11→use crate::jjrt_types::*;
 12→
 13→/// Check if string contains only URL-safe base64 characters
 14→#[allow(dead_code)]
 15→pub(crate) fn zjjrg_is_base64(s: &str) -> bool {
 16→    s.bytes().all(|b| JJRF_CHARSET.contains(&b))
 17→}
 18→
 19→/// Check if string is valid kebab-case (non-empty, alphanumeric with hyphens, case-insensitive)
 20→#[allow(dead_code)]
 21→pub(crate) fn zjjrg_is_kebab_case(s: &str) -> bool {
 22→    if s.is_empty() {
 23→        return false;
 24→    }
 25→    // Pattern: [a-zA-Z0-9]+(-[a-zA-Z0-9]+)*
 26→    let parts: Vec<&str> = s.split('-').collect();
 27→    for part in parts {
 28→        if part.is_empty() {
 29→            return false;
 30→        }
 31→        if !part.chars().all(|c| c.is_ascii_alphanumeric()) {
 32→            return false;
 33→        }
 34→    }
 35→    true
 36→}
 37→
 38→/// Check if string matches YYMMDD format
 39→#[allow(dead_code)]
 40→pub(crate) fn zjjrg_is_yymmdd(s: &str) -> bool {
 41→    if s.len() != 6 {
 42→        return false;
 43→    }
 44→    s.chars().all(|c| c.is_ascii_digit())
 45→}
 46→
 47→/// Check if string matches YYMMDD-HHMM format
 48→#[allow(dead_code)]
 49→pub(crate) fn zjjrg_is_yymmdd_hhmm(s: &str) -> bool {
 50→    if s.len() != 11 {
 51→        return false;
 52→    }
 53→    let parts: Vec<&str> = s.split('-').collect();
 54→    if parts.len() != 2 {
 55→        return false;
 56→    }
 57→    parts[0].len() == 6
 58→        && parts[0].chars().all(|c| c.is_ascii_digit())
 59→        && parts[1].len() == 4
 60→        && parts[1].chars().all(|c| c.is_ascii_digit())
 61→}
 62→
 63→/// Check if string is valid commit SHA format (used for basis field)
 64→///
 65→/// Length is derived from JJRG_UNKNOWN_BASIS constant.
 66→#[allow(dead_code)]
 67→pub(crate) fn zjjrg_is_commit_sha(s: &str) -> bool {
 68→    s.len() == JJRG_UNKNOWN_BASIS.len() && s.chars().all(|c| c.is_ascii_hexdigit())
 69→}
 70→
 71→/// Validate the Gallops structure
 72→///
 73→/// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
 74→pub fn jjrg_validate(gallops: &jjrg_Gallops) -> Result<(), Vec<String>> {
 75→    let mut errors = Vec::new();
 76→
 77→    // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
 78→    if gallops.next_heat_seed.len() != 2 {
 79→        errors.push(format!(
 80→            "next_heat_seed must be 2 characters, got {}",
 81→            gallops.next_heat_seed.len()
 82→        ));
 83→    } else if !zjjrg_is_base64(&gallops.next_heat_seed) {
 84→        errors.push(format!(
 85→            "next_heat_seed contains invalid base64 characters: '{}'",
 86→            gallops.next_heat_seed
 87→        ));
 88→    }
 89→
 90→    // Rule 2: heats object exists (implicitly satisfied by struct)
 91→
 92→    // Validate each Heat
 93→    for (heat_key, heat) in &gallops.heats {
 94→        zjjrg_validate_heat(heat_key, heat, &mut errors);
 95→    }
 96→
 97→    if errors.is_empty() {
 98→        Ok(())
 99→    } else {
100→        Err(errors)
101→    }
102→}
103→
104→fn zjjrg_validate_heat(heat_key: &str, heat: &jjrg_Heat, errors: &mut Vec<String>) {
105→    let heat_ctx = format!("Heat '{}'", heat_key);
106→
107→    // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
108→    if !heat_key.starts_with('₣') {
109→        errors.push(format!("{}: key must start with '₣'", heat_ctx));
110→    } else {
111→        let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
112→        if suffix.len() != 2 {
113→            errors.push(format!(
114→                "{}: key must have 2 base64 chars after '₣', got {}",
115→                heat_ctx,
116→                suffix.len()
117→            ));
118→        } else if !zjjrg_is_base64(suffix) {
119→            errors.push(format!(
120→                "{}: key contains invalid base64 characters",
121→                heat_ctx
122→            ));
123→        }
124→    }
125→
126→    // Rule 4: Required Heat fields
127→    // silks (non-empty alphanumeric-kebab)
128→    if !zjjrg_is_kebab_case(&heat.silks) {
129→        errors.push(format!(
130→            "{}: silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'",
131→            heat_ctx, heat.silks
132→        ));
133→    }
134→
135→    // creation_time (YYMMDD)
136→    if !zjjrg_is_yymmdd(&heat.creation_time) {
137→        errors.push(format!(
138→            "{}: creation_time must be YYMMDD format, got '{}'",
139→            heat_ctx, heat.creation_time
140→        ));
141→    }
142→
143→    // status (validated by serde enum)
144→
145→    // next_pace_seed (3 URL-safe base64 characters)
146→    if heat.next_pace_seed.len() != 3 {
147→        errors.push(format!(
148→            "{}: next_pace_seed must be 3 characters, got {}",
149→            heat_ctx,
150→            heat.next_pace_seed.len()
151→        ));
152→    } else if !zjjrg_is_base64(&heat.next_pace_seed) {
153→        errors.push(format!(
154→            "{}: next_pace_seed contains invalid base64 characters",
155→            heat_ctx
156→        ));
157→    }
158→
159→    // Extract heat identity (base64 part without prefix) for pace validation
160→    let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
161→        Some(&heat_key[3..]) // ₣ is 3 bytes
162→    } else {
163→        None
164→    };
165→
166→    // Rule 5: order array and paces object must have identical key sets
167→    let order_set: HashSet<&String> = heat.order.iter().collect();
168→    let _paces_set: HashSet<&String> = heat.paces.keys().collect();
169→
170→    if order_set.len() != heat.order.len() {
171→        errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
172→    }
173→
174→    let in_order_not_paces: Vec<_> = heat
175→        .order
176→        .iter()
177→        .filter(|k| !heat.paces.contains_key(*k))
178→        .collect();
179→    let in_paces_not_order: Vec<_> = heat
180→        .paces
181→        .keys()
182→        .filter(|k| !order_set.contains(k))
183→        .collect();
184→
185→    if !in_order_not_paces.is_empty() {
186→        errors.push(format!(
187→            "{}: order contains keys not in paces: {:?}",
188→            heat_ctx, in_order_not_paces
189→        ));
190→    }
191→    if !in_paces_not_order.is_empty() {
192→        errors.push(format!(
193→            "{}: paces contains keys not in order: {:?}",
194→            heat_ctx, in_paces_not_order
195→        ));
196→    }
197→
198→    // Validate each Pace
199→    for (pace_key, pace) in &heat.paces {
200→        zjjrg_validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
201→    }
202→}
203→
204→fn zjjrg_validate_pace(
205→    heat_ctx: &str,
206→    heat_identity: Option<&str>,
207→    pace_key: &str,
208→    pace: &jjrg_Pace,
209→    errors: &mut Vec<String>,
210→) {
211→    let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
212→
213→    // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
214→    if !pace_key.starts_with('₢') {
215→        errors.push(format!("{}: key must start with '₢'", pace_ctx));
216→    } else {
217→        let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
218→        if suffix.len() != 5 {
219→            errors.push(format!(
220→                "{}: key must have 5 base64 chars after '₢', got {}",
221→                pace_ctx,
222→                suffix.len()
223→            ));
224→        } else {
225→            if !zjjrg_is_base64(suffix) {
226→                errors.push(format!(
227→                    "{}: key contains invalid base64 characters",
228→                    pace_ctx
229→                ));
230→            }
231→            // Pace must embed parent Heat identity (first 2 chars)
232→            if let Some(heat_id) = heat_identity {
233→                if !suffix.starts_with(heat_id) {
234→                    errors.push(format!(
235→                        "{}: key must embed parent heat identity '{}', got '{}'",
236→                        pace_ctx,
237→                        heat_id,
238→                        &suffix[..2.min(suffix.len())]
239→                    ));
240→                }
241→            }
242→        }
243→    }
244→
245→    // Rule 7: tacks must be non-empty array
246→    if pace.tacks.is_empty() {
247→        errors.push(format!("{}: tacks array must not be empty", pace_ctx));
248→    }
249→
250→    // Validate each Tack
251→    for (i, tack) in pace.tacks.iter().enumerate() {
252→        zjjrg_validate_tack(&pace_ctx, i, tack, errors);
253→    }
254→}
255→
256→fn zjjrg_validate_tack(pace_ctx: &str, index: usize, tack: &jjrg_Tack, errors: &mut Vec<String>) {
257→    let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
258→
259→    // Rule 8: ts must be YYMMDD-HHMM
260→    if !zjjrg_is_yymmdd_hhmm(&tack.ts) {
261→        errors.push(format!(
262→            "{}: ts must be YYMMDD-HHMM format, got '{}'",
263→            tack_ctx, tack.ts
264→        ));
265→    }
266→
267→    // Rule 8: text must be non-empty
268→    if tack.text.is_empty() {
269→        errors.push(format!("{}: text must not be empty", tack_ctx));
270→    }
271→
272→    // Rule 8: silks must be non-empty alphanumeric-kebab
273→    if !zjjrg_is_kebab_case(&tack.silks) {
274→        errors.push(format!(
275→            "{}: silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'",
276→            tack_ctx, tack.silks
277→        ));
278→    }
279→
280→    // Rule 8: basis must be valid format (7 hex chars)
281→    if !zjjrg_is_commit_sha(&tack.basis) {
282→        errors.push(format!(
283→            "{}: basis must be 7 hex characters, got '{}'",
284→            tack_ctx, tack.basis
285→        ));
286→    }
287→
288→    // Rule 9: direction presence depends on state
289→    match tack.state {
290→        jjrg_PaceState::Bridled => {
291→            match &tack.direction {
292→                None => {
293→                    errors.push(format!(
294→                        "{}: direction is required when state is 'bridled'",
295→                        tack_ctx
296→                    ));
297→                }
298→                Some(d) if d.is_empty() => {
299→                    errors.push(format!(
300→                        "{}: direction must not be empty when state is 'bridled'",
301→                        tack_ctx
302→                    ));
303→                }
304→                _ => {}
305→            }
306→        }
307→        _ => {
308→            if tack.direction.is_some() {
309→                errors.push(format!(
310→                    "{}: direction must be absent when state is not 'bridled'",
311→                    tack_ctx
312→                ));
313→            }
314→        }
315→    }
316→}
